private static int findLongest(String str1, String str2) {
    int s1Len = str1.length();
    int s2Len = str2.length();
    if (s1Len == 0 || s2Len == 0)
        return 0;
    int[][] dp = new int[s1Len][s2Len];
    int i, j;
    int longest = 0;
    for (i = 0; i < s1Len; i++) {
        for (j = 0; j < s2Len; j++) {
            dp[i][j] = 0;
        }
    }
    for (i = 0; i < s1Len; i++) {
        for (j = 0; j < s2Len; j++) {
            if (str1.charAt(i) == str2.charAt(j)) {
                if (i == 0 || j == 0) {
                    dp[i][j] = 1;
                } else {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                }
                longest = (longest > dp[i][j]) ? longest : dp[i][j];
            }
        }
