    long x0 = 1, y0 = 0, x1 = 0, y1 = 1, x2, y2;
    long r = a % n;
    long q = (a - r) / n;
    while (r > 0) {
        x2 = x0 - q * x1;
        y2 = y0 - q * y1;
        x0 = x1;
        y0 = y1;
        x1 = x2;
        y1 = y2;
