                if (i == 0 || j == 0) {
                    dp[i][j] = 1;
                } else {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                }
                longest = (longest > dp[i][j]) ? longest : dp[i][j];
            }
        }
    }
