import java.util.Scanner;
public class Main {
	private static int[][] map = new int[9][9];

	public static void main(String[] args) {
		Scanner scanner = new Scanner(System.in);
		for (int i = 0; i < 9; i++) {
			String buf = scanner.next();
			char[] num = buf.toCharArray();
			for (int j = 0; j < 9; j++) {
				map[i][j] = num[j] - 48;
			}
		}
		scanner.close();
		backTrack(0, 0);
	}

	private static void backTrack(int x, int y) {
		if (x == 9 && y == 0) {
			for (int i = 0; i < 9; i++) {
				for (int j = 0; j < 9; j++) {
					System.out.print(map[i][j] + " ");
				}
				System.out.println();
			}
			System.exit(0);
		} else {
			// 还没填数
			if (map[x][y] == 0) {
				for (int i = 1; i <= 9; i++) {
					map[x][y] = i;
					if (!isRowCollision(x, y) && !isColumnCollision(x, y) && !is3x3Collision(x, y)) {
						// 从左到右，从上到下填
						backTrack(x + (y + 1) / 9, (y + 1) % 9);
					}
					map[x][y] = 0;
				}
			} else {
				// 填了的就继续下一个
				backTrack(x + (y + 1) / 9, (y + 1) % 9);
			}
		}
	}

	private static boolean isRowCollision(int x, int y) {
		for (int i = 0; i < 9; i++) {
			if (map[x][y] == map[x][i] && y != i) {
				return true;
			}
		}
		return false;
	}

	private static boolean isColumnCollision(int x, int y) {
		for (int i = 0; i < 9; i++) {
			if (map[x][y] == map[i][y] && x != i) {
				return true;
			}
		}
		return false;
	}

	private static boolean is3x3Collision(int x, int y) {
		int start, end;
		if (x < 3) {
			start = 0;
		} else if (x < 6) {
			start = 3;
		} else {
			start = 6;
		}

		if (y < 3) {
			end = 0;
		} else if (y < 6) {
			end = 3;
		} else {
			end = 6;
		}

		for (int i = start; i < start + 3; i++) {
			for (int j = end; j < end + 3; j++) {
				if (map[i][j] == map[x][y] && i != x && j != y) {
					return true;
				}
			}
		}
		return false;
	}
}
