	public static String dec2hex(int dec) {
		String hex = "";
		String tmp = "";
		do {
			tmp = dec % 16 + "";
			switch (tmp) {
			case "10":
				tmp = "A";
				break;
			case "11":
				tmp = "B";
				break;
			case "12":
				tmp = "C";
				break;
			case "13":
				tmp = "D";
				break;
			case "14":
				tmp = "E";
				break;
			case "15":
				tmp = "F";
				break;
			}
			hex = tmp + hex;
			dec = dec / 16;
		} while (dec != 0);
		return hex;
	}
}
