	public static String dec2hex(int dec) {
		String hex = "";
		String tmp = "";
		do {
			tmp = dec % 16 + "";
			switch (tmp) {
			case "10":
				tmp = "A";
				break;
			case "11":
				tmp = "B";
				break;
			case "12":
				tmp = "C";
				break;
