		}
		scanner.close();
	}

	public static long hex2dec(String hex) {
		int tmp = 0;
		long dec = 0;
		for (int i = 0; i < hex.length(); i++) {
			switch (Character.toUpperCase(hex.charAt(i))) {
			case 'A':
				tmp = 10;
				break;
			case 'B':
				tmp = 11;
				break;
			case 'C':
				tmp = 12;
				break;
			case 'D':
				tmp = 13;
				break;
			case 'E':
				tmp = 14;
				break;
			case 'F':
				tmp = 15;
				break;
			default:
				tmp = (int) hex.charAt(i) - 48;
				break;
			}
			dec += tmp * Math.pow(16, hex.length() - i - 1);
		}
		return dec;
	}
}
