public class Main {
	private static int solution = 0;
	private static int[] number = new int[] { 1, 2, 3, 4, 5, 6, 7, 8, 9 };

	public static void main(String[] args) {
		backTrack(0);
		System.out.println(solution);
	}

	private static void backTrack(int depth) {
		if (depth == 9) {
			int A = number[0];
			int B = number[1];
			int C = number[2];
			int DEF = number[3] * 100 + number[4] * 10 + number[5];
			int GHI = number[6] * 100 + number[7] * 10 + number[8];
			if (GHI * B + DEF * C == (10 - A) * C * GHI) {
				solution++;
			}
		} else {
			for (int i = depth; i < 9; i++) {
				swap(number, depth, i);
				backTrack(depth + 1);
				swap(number, depth, i);
			}
		}
	}

	private static void swap(int[] array, int i, int j) {
		int tmp = array[i];
		array[i] = array[j];
		array[j] = tmp;
	}
}
