public class Main {
	private static int solution = 0;
	private static int[] number = new int[5];
	private static int[] isChosen = new int[12];

	public static void main(String args[]) {
		// 从12个数字里选5个数字
		backTrack(0);
		System.out.println(solution);
	}

	private static void backTrack(int n) {
		// 去重
		if (n > 1 && number[n - 1] < number[n - 2]) {
			return;
		}
		if (n == 5) {
			if (isOK()) {
				// printNumber();
				solution++;
			}
		} else {
			for (int i = 0; i < 12; i++) {
				if (isChosen[i] == 0) {
					isChosen[i] = 1;
					number[n] = i;
					backTrack(n + 1);
					isChosen[i] = 0;
				}
			}
		}
	}

	public static boolean isOK() {
		boolean[] isVisit = new boolean[5];
		dfs(isVisit, 0);
		return isVisit[0] && isVisit[1] && isVisit[2] && isVisit[3] && isVisit[4];
	}

	public static void dfs(boolean isVisit[], int i) {
		isVisit[i] = true;
		for (int j = 0; j < isVisit.length; j++) {
			if (!isVisit[j]) {
				if (number[i] / 4 == number[j] / 4 && Math.abs(number[i] - number[j]) == 1) {
					dfs(isVisit, j);
				}
				if (Math.abs(number[i] - number[j]) == 4) {
					dfs(isVisit, j);
				}
			}
		}
	}

	private static void printNumber() {
		for (int i : number) {
			System.out.print(i + " ");
		}
		System.out.println();
	}
}
```

